// Earnings Yield Momentum
// Cổ phiếu có Earnings Yield (Lợi nhuận/Giá) hiện tại cao hơn lịch sử 60 ngày của chính nó
// thường là những cổ phiếu đang bị định giá thấp (Undervalued)
eps_yield = ts_backfill(anl4_afv4_eps_mean, 60) / close;
momentum = ts_rank(eps_yield, 60);

// Xếp hạng trong ngành và trung hòa
signal = group_rank(momentum, industry);
group_neutralize(signal, industry)

// Valuation based on cash flow
// EV/CF thấp cho thấy công ty đang trở nên rẻ so với khả năng tạo ra tiền.
// ts_zscore đo lường mức độ rẻ/đắt tương đối so với lịch sử 63 ngày (1 quý).
// Đổi cashflow mặc định thành cashflow_op (Dòng tiền từ hoạt động kinh doanh) để bám sát thực tế.

ev_cf = enterprise_value / cashflow_op;
signal = group_rank(-ts_zscore(ev_cf, 63), industry);

// Trung hòa rủi ro theo nhóm ngành
group_neutralize(signal, industry)

earnings_yield = ts_backfill(est_eps, 60) / close;
signal = group_rank(ts_rank(earnings_yield, 60), industry);
group_neutralize(signal, industry)

// Intraday Open-Close Reversal
// Hypothesis: strong intraday gains → next-day reversal
intraday  = (close - open) / (open + 0.001);
smooth    = ts_mean(intraday, 3);
signal    = group_rank(-smooth, market);
group_neutralize(signal, market)

// Correlation: EPS estimates vs FCF estimates
// Khác rKWvzA3j: dùng anl4_afv4_eps_mean thay est_ptp
eps_bf = ts_backfill(anl4_afv4_eps_mean, 63);
fcf_bf = ts_backfill(est_fcf, 63);
signal = group_rank(-ts_corr(eps_bf, fcf_bf, 20), market);
group_neutralize(signal, market)

eps_bf = ts_backfill(anl4_afv4_eps_mean, 63);
fcf_bf = ts_backfill(est_fcf, 63);
signal = group_rank(-ts_corr(eps_bf, fcf_bf, 20), industry);
group_neutralize(signal, industry)

// Divergence between revenue and operating cashflow estimates
rev = ts_backfill(revenue, 63);
cf = ts_backfill(cashflow_op, 63);
signal = group_rank(-ts_corr(rev, cf, 20), market);
group_neutralize(signal, market)
